import os
import hashlib
import secrets
import time
from functools import wraps
from datetime import datetime, timedelta

from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import bcrypt

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# Rate limiter setup
limiter = Limiter(
    app=app,
    key_func=get_remote_address,
    default_limits=["200 per day", "50 per hour"],
    storage_uri="memory://",
)

# In-memory stores (use a database in production)
users_db = {}
tokens_db = {}
failed_attempts = {}

# Configuration
TOKEN_EXPIRY_HOURS = 24
MAX_FAILED_ATTEMPTS = 5
LOCKOUT_DURATION_MINUTES = 15


def hash_password(password: str) -> str:
    """Hash a password using bcrypt with a random salt."""
    salt = bcrypt.gensalt(rounds=12)
    hashed = bcrypt.hashpw(password.encode('utf-8'), salt)
    return hashed.decode('utf-8')


def verify_password(password: str, hashed: str) -> bool:
    """Verify a password against its bcrypt hash."""
    return bcrypt.checkpw(password.encode('utf-8'), hashed.encode('utf-8'))


def generate_token(username: str) -> str:
    """Generate a cryptographically secure token."""
    raw_token = secrets.token_urlsafe(64)
    # Store a hash of the token, not the token itself
    token_hash = hashlib.sha256(raw_token.encode('utf-8')).hexdigest()
    tokens_db[token_hash] = {
        'username': username,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(hours=TOKEN_EXPIRY_HOURS),
    }
    return raw_token


def validate_token(raw_token: str) -> dict | None:
    """Validate a token and return the associated user info, or None."""
    token_hash = hashlib.sha256(raw_token.encode('utf-8')).hexdigest()
    token_data = tokens_db.get(token_hash)
    if token_data is None:
        return None
    if datetime.utcnow() > token_data['expires_at']:
        # Token expired, remove it
        del tokens_db[token_hash]
        return None
    return token_data


def revoke_token(raw_token: str) -> bool:
    """Revoke a token."""
    token_hash = hashlib.sha256(raw_token.encode('utf-8')).hexdigest()
    if token_hash in tokens_db:
        del tokens_db[token_hash]
        return True
    return False


def is_account_locked(username: str) -> bool:
    """Check if an account is locked due to too many failed attempts."""
    if username not in failed_attempts:
        return False
    attempts_info = failed_attempts[username]
    if attempts_info['count'] >= MAX_FAILED_ATTEMPTS:
        lockout_until = attempts_info['last_attempt'] + timedelta(minutes=LOCKOUT_DURATION_MINUTES)
        if datetime.utcnow() < lockout_until:
            return True
        else:
            # Lockout period expired, reset
            del failed_attempts[username]
            return False
    return False


def record_failed_attempt(username: str):
    """Record a failed login attempt."""
    if username not in failed_attempts:
        failed_attempts[username] = {'count': 0, 'last_attempt': None}
    failed_attempts[username]['count'] += 1
    failed_attempts[username]['last_attempt'] = datetime.utcnow()


def clear_failed_attempts(username: str):
    """Clear failed attempts after successful login."""
    if username in failed_attempts:
        del failed_attempts[username]


def validate_password_strength(password: str) -> tuple[bool, str]:
    """Validate password meets minimum strength requirements."""
    if len(password) < 8:
        return False, "Password must be at least 8 characters long."
    if not any(c.isupper() for c in password):
        return False, "Password must contain at least one uppercase letter."
    if not any(c.islower() for c in password):
        return False, "Password must contain at least one lowercase letter."
    if not any(c.isdigit() for c in password):
        return False, "Password must contain at least one digit."
    if not any(c in '!@#$%^&*()_+-=[]{}|;:,.<>?' for c in password):
        return False, "Password must contain at least one special character."
    return True, "Password is strong enough."


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header:
            return jsonify({'error': 'Authorization header is missing.'}), 401

        parts = auth_header.split()
        if len(parts) != 2 or parts[0].lower() != 'bearer':
            return jsonify({'error': 'Invalid authorization header format. Use: Bearer <token>'}), 401

        raw_token = parts[1]
        token_data = validate_token(raw_token)
        if token_data is None:
            return jsonify({'error': 'Invalid or expired token.'}), 401

        # Attach user info to request
        request.current_user = token_data['username']
        request.token = raw_token
        return f(*args, **kwargs)
    return decorated


@app.route('/api/register', methods=['POST'])
@limiter.limit("5 per minute")
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON.'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required.'}), 400

    if len(username) < 3 or len(username) > 50:
        return jsonify({'error': 'Username must be between 3 and 50 characters.'}), 400

    if username in users_db:
        # Use constant-time-like response to avoid user enumeration
        # We add a small artificial delay
        time.sleep(0.1)
        return jsonify({'error': 'Username already exists.'}), 409

    # Validate password strength
    is_strong, message = validate_password_strength(password)
    if not is_strong:
        return jsonify({'error': message}), 400

    # Hash password and store user
    hashed_pw = hash_password(password)
    users_db[username] = {
        'password_hash': hashed_pw,
        'created_at': datetime.utcnow().isoformat(),
    }

    return jsonify({'message': f'User "{username}" registered successfully.'}), 201


@app.route('/api/login', methods=['POST'])
@limiter.limit("10 per minute")
def login():
    """Authenticate user and return a token."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON.'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required.'}), 400

    # Check account lockout
    if is_account_locked(username):
        return jsonify({
            'error': f'Account is locked due to too many failed attempts. Try again in {LOCKOUT_DURATION_MINUTES} minutes.'
        }), 429

    # Verify credentials
    user = users_db.get(username)
    if user is None or not verify_password(password, user['password_hash']):
        record_failed_attempt(username)
        remaining = MAX_FAILED_ATTEMPTS - failed_attempts.get(username, {}).get('count', 0)
        # Generic error message to prevent user enumeration
        return jsonify({
            'error': 'Invalid username or password.',
            'remaining_attempts': max(remaining, 0),
        }), 401

    # Successful login
    clear_failed_attempts(username)
    token = generate_token(username)

    return jsonify({
        'message': 'Login successful.',
        'token': token,
        'token_type': 'Bearer',
        'expires_in_hours': TOKEN_EXPIRY_HOURS,
    }), 200


@app.route('/api/logout', methods=['POST'])
@token_required
def logout():
    """Revoke the current token."""
    revoke_token(request.token)
    return jsonify({'message': 'Logged out successfully. Token revoked.'}), 200


@app.route('/api/logout-all', methods=['POST'])
@token_required
def logout_all():
    """Revoke all tokens for the current user."""
    username = request.current_user
    tokens_to_remove = [
        token_hash for token_hash, data in tokens_db.items()
        if data['username'] == username
    ]
    for token_hash in tokens_to_remove:
        del tokens_db[token_hash]

    return jsonify({
        'message': f'All sessions revoked. {len(tokens_to_remove)} token(s) invalidated.'
    }), 200


