@app.route('/api/profile', methods=['GET'])
@token_required
def profile():
    """Get the current user's profile."""
    username = request.current_user
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found.'}), 404

    # Count active tokens for this user
    active_sessions = sum(
        1 for data in tokens_db.values()
        if data['username'] == username and datetime.utcnow() < data['expires_at']
    )

    return jsonify({
        'username': username,
        'created_at': user['created_at'],
        'active_sessions': active_sessions,
    }), 200


@app.route('/api/change-password', methods=['POST'])
@token_required
@limiter.limit("3 per minute")
def change_password():
    """Change the current user's password."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON.'}), 400

    current_password = data.get('current_password', '')
    new_password = data.get('new_password', '')

    if not current_password or not new_password:
        return jsonify({'error': 'Current password and new password are required.'}), 400

    username = request.current_user
    user = users_db.get(username)

    if not verify_password(current_password, user['password_hash']):
        return jsonify({'error': 'Current password is incorrect.'}), 401

    # Validate new password strength
    is_strong, message = validate_password_strength(new_password)
    if not is_strong:
        return jsonify({'error': message}), 400

    # Update password
    users_db[username]['password_hash'] = hash_password(new_password)

    # Revoke all existing tokens (force re-login)
    tokens_to_remove = [
        token_hash for token_hash, data in tokens_db.items()
        if data['username'] == username
    ]
    for token_hash in tokens_to_remove:
        del tokens_db[token_hash]

    # Generate a new token for the current session
    new_token = generate_token(username)

    return jsonify({
        'message': 'Password changed successfully. All previous sessions have been revoked.',
        'token': new_token,
        'token_type': 'Bearer',
    }), 200


