# Cleanup expired tokens periodically (simple approach)
@app.before_request
def cleanup_expired_tokens():
    """Remove expired tokens on each request (simple cleanup strategy)."""
    now = datetime.utcnow()
    expired = [
        token_hash for token_hash, data in tokens_db.items()
        if now > data['expires_at']
    ]
    for token_hash in expired:
        del tokens_db[token_hash]


